DECLARE @schemaName NVARCHAR(20) = '@{variables('dbschema')}';
DECLARE @tablePrefix NVARCHAR(148) = '@{variables('prefix')}';
DECLARE @container NVARCHAR(70) = '@{pipeline().parameters.container}';
DECLARE @folder NVARCHAR(70) = '@{pipeline().parameters.folder}';
DECLARE @runid NVARCHAR(40) = '@{pipeline().RunId}';
DECLARE @entity NVARCHAR(200) = '@{item().Entity}';

DECLARE @UpdateVersionLog NVARCHAR(MAX) =
'UPDATE '+ @schemaName + '.' + @tablePrefix + 'DataverseToSQLVerionLog
SET
PipelineRunId = ''' + @runid + ''', prefolder = ''' + @folder + ''', premaxversion = maxversion, maxversion = (SELECT MAX(versionnumber) FROM ' + @schemaName + '.' + @tablePrefix + @entity + ') 
WHERE Entity = '+ '''' + @entity + ''''
;
EXECUTE sp_executesql @UpdateVersionLog;

USE SCHEMA PUBLIC;
